text:
{
  "formal_minutes": {
    "decisions": [
      {
        "항목": "공개 릴리즈 목표일",
        "내용": "스모크 테스트 통과를 전제로 공개 릴리즈 목표를 금요일 15:00 KST로 확정한다."
      },
      {
        "항목": "릴리즈 조건",
        "내용": "수요일 안배포 제안은 거부되었고, 스모크 테스트가 통과한 후에만 릴리즈 진행으로 본다."
      },
      {
        "항목": "패키지명 불일치 처리",
        "내용": "`smoke-theme-pack.mjs`에서 packageName 불일치를 무시하지 않는다. 불일치가 발생하면 먼저 패키지 설정/계약을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "항목": "Hara의 스크립트 변경 제안",
        "내용": "`smoke-theme-pack.mjs`를 수정해 packageName mismatch를 무시하자는 제안은 회의에서 반려."
      }
    ],
    "internal_stretch_goals": [
      {
        "항목": "수요일 공개 대비",
        "내용": "수요일 릴리즈는 내부 목표(스트레치)로만 언급되었고 확정 목표가 아님."
      }
    ],
    "non_decisions": [
      {
        "항목": "README 설치 가이드 검토",
        "내용": "목요일 검토 희망이 있었으나 최종 담당자·확정 기한이 지정되지 않음."
      },
      {
        "항목": "Hara의 tarball 경로 확인",
        "내용": "Minjun의 스모크 결과 게시 후 확인 예정으로, 구체적 기한은 미정."
      }
    ],
    "risks": [
      {
        "항목": "잘못된 tarball 경로",
        "내용": "tarball 경로가 잘못되면 릴리즈 지연 가능성."
      },
      {
        "항목": "README 설치 가이드 최신성",
        "내용": "README 설치 단계가 오래되면 릴리즈 노트가 사용자 오해를 유발할 수 있음."
      }
    ],
    "open_questions": [
      {
        "항목": "최종 릴리즈 승인 권한",
        "내용": "최종 릴리즈 승인자가 누구인지 미정."
      },
      {
        "항목": "수요일 스트레치 목표 언급",
        "내용": "릴리스 노트에 내부 수요일 목표를 표시할지 여부 미정."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확인 필요",
      "source_certainty": "high"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 Minjun의 스모크 결과 게시 여부 및 성공/실패 상태 확인",
      "Doyun의 action_items.md 실패 트리아지 노트 작성 완료 여부 확인",
      "최종 릴리즈 승인 권한자 지정",
      "README 설치 단계 최신성 점검 담당자/기한 확정",
      "Hara의 tarball 경로 확인 완료 확인"
    ],
    "what_not_to_invent": [
      "고객/파트너 명칭, 예산 수치, 보안 사고, 실서비스 장애, 법적 승인 필요성, 소유자 미지정 사실, 기한 미기재 항목의 확정 기한은 회의록에 없으므로 추가로 추정하지 않는다.",
      "릴리즈 노트에 수요일 목표를 넣을지 여부는 오픈 질문으로 남아 있으므로 확정 사실로 기록하지 않는다."
    ]
  },
  "non_invention_rules": [
    "기록에는 제공된 공개 안전 합성 회의 데이터만 사용한다.",
    "명시되지 않은 고객, 예산, 보안 사건, 장애, 법률 승인, 최종 책임자, 확정 마감일은 생성하지 않는다.",
    "시간/기한은 원문에서 제시된 KST 값만 사용하고 임의 추론을 피한다.",
    "확정된 항목과 미확정 항목(질문/미정)을 구분해 기록한다."
  ]
}
